import{_ as a,o as s,c as t,a2 as i}from"./chunks/framework.CZqXuAiL.js";const k=JSON.parse('{"title":"FAQ","description":"","frontmatter":{},"headers":[],"relativePath":"openshield-xdp/getting-started/faq.md","filePath":"openshield-xdp/getting-started/faq.md","lastUpdated":1782454750000}'),n={name:"openshield-xdp/getting-started/faq.md"};function r(o,e,h,l,d,p){return s(),t("div",null,[...e[0]||(e[0]=[i(`<h1 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h1><h2 id="what-kernel-version-do-i-need" tabindex="-1">What kernel version do I need? <a class="header-anchor" href="#what-kernel-version-do-i-need" aria-label="Permalink to &quot;What kernel version do I need?&quot;">​</a></h2><p>Linux ≥ 5.8. For freplace support (hot-patching), ≥ 5.11 with <code>CONFIG_DEBUG_INFO_BTF=y</code>.</p><h2 id="does-this-replace-iptables-nftables" tabindex="-1">Does this replace iptables/nftables? <a class="header-anchor" href="#does-this-replace-iptables-nftables" aria-label="Permalink to &quot;Does this replace iptables/nftables?&quot;">​</a></h2><p>No. OpenShield operates at the XDP layer (before kernel skb allocation). iptables/nftables operate at Netfilter hooks much later in the stack. They complement each other.</p><h2 id="what-s-the-performance-overhead" tabindex="-1">What&#39;s the performance overhead? <a class="header-anchor" href="#what-s-the-performance-overhead" aria-label="Permalink to &quot;What&#39;s the performance overhead?&quot;">​</a></h2><p>~300–500 ns per packet under normal traffic. ~1–2 μs with all modules active. A single core handles 10M PPS at ~50–70% utilization.</p><h2 id="can-synproxy-break-legitimate-connections" tabindex="-1">Can SYNPROXY break legitimate connections? <a class="header-anchor" href="#can-synproxy-break-legitimate-connections" aria-label="Permalink to &quot;Can SYNPROXY break legitimate connections?&quot;">​</a></h2><p>SYNPROXY is off by default. When enabled, it intercepts only the initial SYN and returning ACK. The kernel completes the real handshake once the cookie is verified. TCP options are preserved.</p><h2 id="does-this-support-xdp-hardware-offload" tabindex="-1">Does this support XDP hardware offload? <a class="header-anchor" href="#does-this-support-xdp-hardware-offload" aria-label="Permalink to &quot;Does this support XDP hardware offload?&quot;">​</a></h2><p><code>xdp_mode: auto</code> tries hardware offload first, then native, then generic. Requires smart NIC (Netronome, Intel E810, Mellanox ConnectX with upstream driver).</p><h2 id="how-do-i-test-without-a-real-attack" tabindex="-1">How do I test without a real attack? <a class="header-anchor" href="#how-do-i-test-without-a-real-attack" aria-label="Permalink to &quot;How do I test without a real attack?&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># SYN flood</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">hping3</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -S</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --flood</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 80</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">targe</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">t</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># UDP flood</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">hping3</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --udp</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --flood</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 53</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">targe</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">t</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Watch the dashboard</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openshield-tui</span></span></code></pre></div><h2 id="why-does-the-verifier-reject-on-some-kernels" tabindex="-1">Why does the verifier reject on some kernels? <a class="header-anchor" href="#why-does-the-verifier-reject-on-some-kernels" aria-label="Permalink to &quot;Why does the verifier reject on some kernels?&quot;">​</a></h2><p>Different kernel versions have different verifier strictness. The most common cause is stale pinned maps from a previous version. Run <code>sudo openshield fix</code>.</p><h2 id="can-i-run-this-alongside-a-kubernetes-cni" tabindex="-1">Can I run this alongside a Kubernetes CNI? <a class="header-anchor" href="#can-i-run-this-alongside-a-kubernetes-cni" aria-label="Permalink to &quot;Can I run this alongside a Kubernetes CNI?&quot;">​</a></h2><p>Yes. XDP programs run on individual interfaces. They don&#39;t conflict with Cilium, Calico, or other CNIs that operate at different hook points.</p><h2 id="next-steps" tabindex="-1">Next steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next steps&quot;">​</a></h2><ul><li><a href="/pingless-studios-docs/openshield-xdp/getting-started/installation">Installation</a></li><li><a href="/pingless-studios-docs/openshield-xdp/getting-started/quick-start">Quick Start</a></li></ul>`,19)])])}const f=a(n,[["render",r]]);export{k as __pageData,f as default};
